module mux8_to_1 (  
    input [7:0] data_in,     // 8 data inputs  
    input [2:0] s,     // 3 select lines  
    output reg y       // output  
);  
    always @(*) begin  
        case(s)  
            3'b000: y = data_in[0];  
            3'b001: y = data_in[1];  
            3'b010: y = data_in[2];  
            3'b011: y = data_in[3];  
            3'b100: y = data_in[4];  
            3'b101: y = data_in[5];  
            3'b110: y = data_in[6];  
            3'b111: y = data_in[7];  
            default: y = 1'b0;  
        endcase  
    end  
endmodule
